import { Component, OnDestroy, OnInit } from '@angular/core';
import { SuccessMessageService } from './succuss-response-shared.component.service';
import { AuthSessionService } from '../../../auth/auth-session.service';

@Component({
  selector: 'app-pa-form-submit-success-page',
  standalone: true,
  imports: [],
  templateUrl: './pa-form-submit-success-page.component.html',
  styleUrl: './pa-form-submit-success-page.component.css'
})
export class PaFormSubmitSuccessPageComponent implements OnInit, OnDestroy {
  successMessage: string = '';

  constructor(
    private successMessageService: SuccessMessageService, private authSessionService: AuthSessionService
  ) { }

  ngOnInit(): void {
    this.successMessageService.successMessage$.subscribe((message) => {
      this.successMessage =
        message ||
        "Thank you for your submission. We have received your information and will process it shortly.";
    });

    this.authSessionService.clearSessionOwner();

    window.addEventListener('popstate', this.handleBackNavigation);
  }

  private handleBackNavigation = () => {
    this.authSessionService.exitDisbursementMode();
    this.authSessionService.clearSessionOwner();
    location.replace('/login');
  };

  ngOnDestroy(): void {
    window.removeEventListener('popstate', this.handleBackNavigation);
  }
}
